import React, { useEffect, useState } from "react";
import API from "../services/api";
import Navbar from "../components/Navbar";

function Animals() {
  const role = localStorage.getItem("role");
  const isAdmin = role === "ADMIN";

  const [animals, setAnimals] = useState([]);
  const [enclosures, setEnclosures] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    species: "",
    age: "",
    gender: "",
    foodType: "",
    healthStatus: "",
    arrivalDate: "",
    enclosureId: "",
  });

  useEffect(() => {
    fetchAnimals();
    fetchEnclosures();
  }, []);

  const fetchAnimals = async () => {
    try {
      const res = await API.get("/animals");
      setAnimals(res.data);
    } catch (error) {
      console.error("Error fetching animals:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchEnclosures = async () => {
    try {
      const res = await API.get("/enclosures");
      setEnclosures(res.data);
    } catch (error) {
      console.error("Error fetching enclosures:", error);
    }
  };

  const resetForm = () => {
    setFormData({
      name: "",
      species: "",
      age: "",
      gender: "",
      foodType: "",
      healthStatus: "",
      arrivalDate: "",
      enclosureId: "",
    });
    setEditingId(null);
  };

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      name: formData.name,
      species: formData.species,
      age: Number(formData.age),
      gender: formData.gender,
      foodType: formData.foodType,
      healthStatus: formData.healthStatus,
      arrivalDate: formData.arrivalDate,
      enclosure: formData.enclosureId ? { id: Number(formData.enclosureId) } : null,
    };

    try {
      if (editingId) {
        await API.put(`/animals/${editingId}`, payload);
        alert("Animal updated successfully");
      } else {
        await API.post("/animals", payload);
        alert("Animal added successfully");
      }

      resetForm();
      fetchAnimals();
    } catch (error) {
      console.error("Error saving animal:", error);
      const data = error.response?.data;
      if (data && typeof data === "object") {
        alert(Object.values(data)[0]);
      } else {
        alert("Failed to save animal");
      }
    }
  };

  const handleEdit = (animal) => {
    setEditingId(animal.id);
    setFormData({
      name: animal.name || "",
      species: animal.species || "",
      age: animal.age || "",
      gender: animal.gender || "",
      foodType: animal.foodType || "",
      healthStatus: animal.healthStatus || "",
      arrivalDate: animal.arrivalDate || "",
      enclosureId: animal.enclosure?.id || "",
    });

    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm("Are you sure you want to delete this animal?");
    if (!confirmDelete) return;

    try {
      await API.delete(`/animals/${id}`);
      alert("Animal deleted successfully");
      fetchAnimals();
    } catch (error) {
      console.error("Error deleting animal:", error);
      alert("Failed to delete animal");
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <div style={styles.header}>
          <h1 style={styles.title}>Animals Management</h1>
          <p style={styles.subtitle}>
            {isAdmin
              ? "Add, update, view, and manage zoo animals from one place."
              : "View all zoo animals and their details."}
          </p>
        </div>

        {isAdmin && (
          <div style={styles.formCard}>
            <h2 style={styles.cardTitle}>
              {editingId ? "Update Animal" : "Add New Animal"}
            </h2>

            <form onSubmit={handleSubmit} style={styles.formGrid}>
              <input type="text" name="name" placeholder="Animal Name" value={formData.name} onChange={handleChange} style={styles.input} />
              <input type="text" name="species" placeholder="Species" value={formData.species} onChange={handleChange} style={styles.input} />
              <input type="number" name="age" placeholder="Age" value={formData.age} onChange={handleChange} style={styles.input} />

              <select name="gender" value={formData.gender} onChange={handleChange} style={styles.input}>
                <option value="">Select Gender</option>
                <option value="Male">Male</option>
                <option value="Female">Female</option>
              </select>

              <input type="text" name="foodType" placeholder="Food Type" value={formData.foodType} onChange={handleChange} style={styles.input} />
              <input type="text" name="healthStatus" placeholder="Health Status" value={formData.healthStatus} onChange={handleChange} style={styles.input} />
              <input type="date" name="arrivalDate" value={formData.arrivalDate} onChange={handleChange} style={styles.input} />

              <select name="enclosureId" value={formData.enclosureId} onChange={handleChange} style={styles.input}>
                <option value="">Select Enclosure</option>
                {enclosures.map((enclosure) => (
                  <option key={enclosure.id} value={enclosure.id}>
                    {enclosure.name}
                  </option>
                ))}
              </select>

              <div style={styles.buttonRow}>
                <button type="submit" style={styles.primaryBtn}>
                  {editingId ? "Update Animal" : "Add Animal"}
                </button>

                {editingId && (
                  <button type="button" style={styles.cancelBtn} onClick={resetForm}>
                    Cancel
                  </button>
                )}
              </div>
            </form>
          </div>
        )}

        <div style={styles.listSection}>
          <h2 style={styles.cardTitle}>Animals List</h2>

          {loading ? (
            <p>Loading animals...</p>
          ) : animals.length === 0 ? (
            <p>No animals found.</p>
          ) : (
            <div style={styles.grid}>
              {animals.map((animal) => (
                <div key={animal.id} style={styles.animalCard}>
                  <h3 style={styles.animalName}>{animal.name}</h3>
                  <p><strong>Species:</strong> {animal.species}</p>
                  <p><strong>Age:</strong> {animal.age}</p>
                  <p><strong>Gender:</strong> {animal.gender}</p>
                  <p><strong>Food:</strong> {animal.foodType}</p>
                  <p><strong>Health:</strong> {animal.healthStatus}</p>
                  <p><strong>Arrival Date:</strong> {animal.arrivalDate}</p>
                  <p><strong>Enclosure:</strong> {animal.enclosure?.name || "Not Assigned"}</p>

                  {isAdmin && (
                    <div style={styles.actionRow}>
                      <button style={styles.editBtn} onClick={() => handleEdit(animal)}>
                        Edit
                      </button>
                      <button style={styles.deleteBtn} onClick={() => handleDelete(animal.id)}>
                        Delete
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: { minHeight: "100vh", background: "linear-gradient(135deg, #eef2ff, #f8fafc)", fontFamily: "Arial, sans-serif" },
  container: { width: "90%", maxWidth: "1200px", margin: "0 auto", padding: "30px 0 50px" },
  header: { background: "linear-gradient(135deg, #ffffff, #eff6ff)", padding: "30px", borderRadius: "20px", boxShadow: "0 10px 24px rgba(0,0,0,0.08)", marginBottom: "25px" },
  title: { fontSize: "2.2rem", color: "#111827", marginBottom: "10px" },
  subtitle: { color: "#4b5563", fontSize: "1rem", lineHeight: "1.7" },
  formCard: { background: "#fff", padding: "25px", borderRadius: "18px", boxShadow: "0 8px 20px rgba(0,0,0,0.08)", marginBottom: "30px" },
  cardTitle: { fontSize: "1.5rem", marginBottom: "20px", color: "#111827" },
  formGrid: { display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: "16px" },
  input: { padding: "13px 15px", borderRadius: "10px", border: "1px solid #cbd5e1", fontSize: "1rem", outline: "none" },
  buttonRow: { display: "flex", gap: "12px", alignItems: "center", flexWrap: "wrap" },
  primaryBtn: { background: "#2563eb", color: "#fff", border: "none", padding: "12px 18px", borderRadius: "10px", cursor: "pointer", fontWeight: "bold" },
  cancelBtn: { background: "#6b7280", color: "#fff", border: "none", padding: "12px 18px", borderRadius: "10px", cursor: "pointer", fontWeight: "bold" },
  listSection: { marginTop: "20px" },
  grid: { display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))", gap: "20px" },
  animalCard: { background: "#fff", borderRadius: "16px", padding: "22px", boxShadow: "0 8px 18px rgba(0,0,0,0.08)", lineHeight: "1.7" },
  animalName: { color: "#111827", marginBottom: "12px" },
  actionRow: { display: "flex", gap: "10px", marginTop: "15px" },
  editBtn: { background: "#f59e0b", color: "#fff", border: "none", padding: "10px 14px", borderRadius: "8px", cursor: "pointer", fontWeight: "bold" },
  deleteBtn: { background: "#dc2626", color: "#fff", border: "none", padding: "10px 14px", borderRadius: "8px", cursor: "pointer", fontWeight: "bold" },
};

export default Animals;
